const body = $json.body || $json;

const safe = (v) => String(v ?? '').trim();
const cleanUrl = (v) => {
  const s = safe(v);
  if (!s || /^(undefined|null|nan)$/i.test(s)) return '';
  if (s.startsWith('//')) return 'https:' + s;
  return s.startsWith('http://') || s.startsWith('https://') ? s : '';
};
const ensureNoBgm = (value) => {
  const prompt = safe(value);
  const rule = 'ABSOLUTELY NO BGM, NO BACKGROUND MUSIC. Pure voice/dialogue and ambient foley only.';
  if (!prompt) return rule;
  return /no\s+(bgm|background music)|without\s+(bgm|background music)/i.test(prompt)
    ? prompt
    : prompt + '\n\n' + rule;
};
const withQuery = (url, params) => {
  const base = cleanUrl(url);
  if (!base) return '';
  const u = new URL(base);
  for (const [k, v] of Object.entries(params)) {
    const s = safe(v);
    if (s) u.searchParams.set(k, s);
  }
  return u.toString();
};
const clampDuration = (value) => {
  const n = Math.round(Number(value) || 8);
  return Math.max(4, Math.min(15, n));
};
const dedupeUrls = (values) => {
  const out = [];
  for (const value of values) {
    const url = cleanUrl(value);
    if (url && !out.includes(url) && out.length < 9) out.push(url);
  }
  return out;
};

const segmentId = safe(body.segment_id);
const taskId = safe(body.task_id);
const requestedModel = safe(body.requested_model || body.requestedModel || body.model);
const rawModel = safe(body.model) || requestedModel || 'veo3-fast';
const isSeedance = /seedance/i.test(rawModel);
const route = isSeedance ? 'seedance' : 'yunwu';
const kieModel = /fast/i.test(rawModel) ? 'bytedance/seedance-2-fast' : 'bytedance/seedance-2';
const firstFrameUrl = cleanUrl(body.first_frame_url || body.firstFrameUrl || body.image_url || body.imageUrl);
const storyboardGridUrl = cleanUrl(body.storyboard_grid_url || body.storyboardGridUrl);
const duration = clampDuration(body.duration);
const aspectRatio = safe(body.aspect_ratio) || '9:16';
const callbackUrl = cleanUrl(body.callback_url);
const apiKey = safe(body.api_key);
const providerApiKey = safe(body.provider_api_key || body.providerApiKey || body.kie_api_key || body.kieApiKey);
const adminToken = safe(body.admin_token);
const workflowId = safe(body.workflow_id) || 'flow_storyboard_veo3';

let prompt = ensureNoBgm(body.prompt);
if (isSeedance && storyboardGridUrl && !/@Image2|@图片2|@图2/.test(prompt)) {
  prompt += '\n\nSeedance 2.0 reference protocol: @Image1 is the current clip first frame or product-replaced reference frame. @Image2 is the full storyboard contact sheet. Additional images may appear as @Image3-@Image9 for product/detail consistency. Use @Image2 only as a timing/composition storyboard reference for this clip; do not generate collage, grid, split-screen, borders, panel numbers, frame labels, or storyboard layout. Final output must be one normal full-screen 9:16 video.';
}

if (!segmentId) throw new Error('segment_id is required');
if (!prompt) throw new Error('prompt is required');
if (!callbackUrl) throw new Error('callback_url is required');
if (!apiKey) throw new Error('api_key is required');
if (isSeedance && !providerApiKey) throw new Error('provider_api_key is required for KIE Seedance');

const incomingReferenceImages = Array.isArray(body.reference_image_urls)
  ? body.reference_image_urls
  : Array.isArray(body.referenceImageUrls)
    ? body.referenceImageUrls
    : [];
const referenceImageUrls = dedupeUrls([firstFrameUrl, storyboardGridUrl, ...incomingReferenceImages]);
const seedanceCallbackUrl = withQuery(callbackUrl, {
  segment_id: segmentId,
  task_id: taskId,
  model: rawModel,
  admin_token: adminToken,
});

const yunwuRequestBody = {
  model: rawModel,
  prompt,
  enhance_prompt: true,
  enable_upsample: true,
  aspect_ratio: aspectRatio,
  duration,
  ...(firstFrameUrl ? { images: [firstFrameUrl] } : {}),
};
const seedanceRequestBody = {
  model: kieModel,
  input: {
    prompt,
    reference_image_urls: referenceImageUrls,
    reference_video_urls: [],
    reference_audio_urls: [],
    generate_audio: false,
    resolution: '720p',
    aspect_ratio: aspectRatio,
    duration,
    web_search: false,
    nsfw_checker: true,
  },
  callBackUrl: seedanceCallbackUrl,
};

return {
  json: {
    segment_id: segmentId,
    task_id: taskId,
    callback_url: callbackUrl,
    api_key: apiKey,
    provider_api_key: providerApiKey,
    admin_token: adminToken,
    workflow_id: workflowId,
    model: requestedModel || rawModel,
    provider: route,
    route,
    isSeedance,
    kieModel,
    firstFrameUrl,
    storyboardGridUrl,
    referenceImageUrls,
    requestBody: isSeedance ? seedanceRequestBody : yunwuRequestBody,
  }
};

const res = $json || {};
const prev = $('准备视频参数').first().json;

const id = res.id || res.data?.id;
const status = res.status || res.data?.status || 'pending';

if (!id) {
  throw new Error('Yunwu video create 失败，未返回 task id: ' + JSON.stringify(res).slice(0, 300));
}

return {
  json: {
    video_task_id: id,
    video_status: status,
    segment_id: prev.segment_id,
    task_id: prev.task_id,
    callback_url: prev.callback_url,
    api_key: prev.api_key,
    admin_token: prev.admin_token,
    workflow_id: prev.workflow_id,
    model: prev.model,
  }
};

const res = $json || {};
const prev = $('准备视频参数').first().json;
const taskId = res.data?.taskId || res.taskId || res.data?.id || '';
if (!taskId) {
  throw new Error('KIE Seedance createTask 失败，未返回 taskId: ' + JSON.stringify(res).slice(0, 500));
}
return {
  json: {
    video_task_id: taskId,
    video_status: 'waiting',
    segment_id: prev.segment_id,
    task_id: prev.task_id,
    callback_url: prev.callback_url,
    api_key: prev.api_key,
    provider_api_key: prev.provider_api_key,
    admin_token: prev.admin_token,
    workflow_id: prev.workflow_id,
    model: prev.model,
    provider: 'kie',
  }
};

const res = $json || {};
const prev = $('提取KIE任务ID').first().json;
const data = res.data && typeof res.data === 'object' ? res.data : {};
const state = String(data.state || res.state || '').toLowerCase();
function parseResultUrl(value) {
  if (!value) return '';
  let parsed = value;
  if (typeof value === 'string') {
    try { parsed = JSON.parse(value); } catch { return ''; }
  }
  const urls = Array.isArray(parsed?.resultUrls) ? parsed.resultUrls : [];
  return typeof urls[0] === 'string' ? urls[0].trim() : '';
}
const videoUrl = parseResultUrl(data.resultJson || res.resultJson);
return {
  json: {
    segment_id: prev.segment_id,
    task_id: prev.task_id,
    status: state === 'success' && videoUrl ? 'success' : state === 'fail' ? 'failed' : 'pending',
    video_url: videoUrl,
    model: prev.model,
    provider: 'kie',
    callback_url: prev.callback_url,
    api_key: prev.api_key,
    admin_token: prev.admin_token,
    generation_params: {
      provider: 'kie',
      provider_task_id: prev.video_task_id,
      provider_state: state || null,
      provider_model: data.model || null,
    },
    raw_state: state,
    raw_response: res,
  }
};
